// Code_AI-SAFE Reducer (final - con Autopick + Confirmación)

const input = $items("Code_Normalize_Stations")[0].json;

const q = (input.q ?? "").toString().trim();
let maxResults = Number(input.maxResults ?? 20);
if (!Number.isFinite(maxResults) || maxResults <= 0) maxResults = 20;
if (maxResults > 20) maxResults = 20; // AI-SAFE cap

// Respuesta del HTTP
const data = $json;
const stationsRaw = Array.isArray(data.stations) ? data.stations : [];

const stations = stationsRaw.slice(0, maxResults).map((s) => ({
  id: s._id ?? null,
  name: s.name ?? null,
  city: s.city ?? null,
  province: s.province ?? null,
  country: s.country ?? null,
  shortcode: s.shortcode ?? null,
  zone: s.zone ?? null,
  disabled: s.disabled ?? null,
  deleted: s.deleted ?? null,
}));

// Heurística bestMatch + tipo de match (para “confianza”)
const qLower = q.toLowerCase();
const qUpper = q.toUpperCase();

let bestMatch = null;
let matchType = null;

bestMatch = stations.find((s) => (s.shortcode ?? "").toUpperCase() === qUpper);
if (bestMatch) matchType = "shortcode_exact";

if (!bestMatch) {
  bestMatch = stations.find((s) => (s.name ?? "").toLowerCase() === qLower);
  if (bestMatch) matchType = "name_exact";
}

if (!bestMatch) {
  bestMatch = stations.find((s) => (s.name ?? "").toLowerCase().includes(qLower));
  if (bestMatch) matchType = "name_includes";
}

// ✅ Autopick (Opción A) + fallback
let selectedStation = null;
let needsConfirmation = false;
let selectionStrategy = null;

if (bestMatch?.id) {
  selectedStation = bestMatch;
  selectionStrategy = `bestMatch:${matchType}`;
} else if (stations.length === 1 && stations[0]?.id) {
  selectedStation = stations[0];
  selectionStrategy = "only_candidate";
} else if (stations.length > 1) {
  // ⚠️ ambigüedad → Opción B (pedir confirmación)
  needsConfirmation = true;
  selectionStrategy = "ambiguous_needs_user_choice";
} else {
  selectionStrategy = "no_results";
}

return [{
  json: {
    ok: true,
    query: q,
    count: data.count ?? stationsRaw.length,
    returned: stationsRaw.length,

    // Para decisiones automáticas:
    bestMatch,
    matchType,

    selectedStationId: selectedStation?.id ?? null,
    selectedStationName: selectedStation?.name ?? null,
    needsConfirmation,
    selectionStrategy,

    // Lista AI-SAFE para mostrar opciones:
    stations,
  }
}];

// Code_Normalize_Stations (FINAL - hardening + soft token validation)

// 1) stationQuery (obligatorio)
const stationQuery =
  ($json.stationQuery ?? $json.name ?? $json.query ?? "")
    .toString()
    .trim();

if (!stationQuery) {
  return [{ json: { ok: false, error: "stationQuery is required" } }];
}

// 2) Normalizar espacios
const q = stationQuery.replace(/\s+/g, " ");

// 3) Token (opcional, validación suave)
const token = ($json.token ?? "").toString().trim();
const tokenMissing = !token;

// 4) maxResults (Trigger puede traer String)
const maxResultsRaw = $json.maxResults ?? 20;
let maxResults = Number(maxResultsRaw);

if (!Number.isFinite(maxResults) || maxResults <= 0) maxResults = 20;
if (maxResults > 20) maxResults = 20; // AI-SAFE cap

// 5) Output normalizado
return [{
  json: {
    ok: true,
    q,
    token,                 // puede ir vacío
    tokenMissing,          // bandera para debugging/decisiones
    warning: tokenMissing ? "token missing: request will rely on x-api-key only" : null,
    maxResults
  }
}];
